sys_script.script:
(function executeRule(current, previous) {
    // Only proceed if status actually changed to cancelled
    if (previous && previous.getValue('appointment_status') == 'cancelled') {
        return;
    }

    // Return the linked Blood Request to the Assigned state (2)
    var bloodRequestId = current.getValue('blood_request');
    if (bloodRequestId) {
        var request = new GlideRecord('x_1920732_lifeli_0_blood_request');
        if (request.get(bloodRequestId)) {
            // Only reset if it was moved beyond Assigned
            request.setValue('state', '2'); // Assigned
            request.update();
        }
    }
})(current, previous);
